import sys, time, random
s = ["⠁","⠂","⠄","⠂"]
c = ["\033[31m","\033[33m","\033[32m","\033[36m","\033[35m"]
p = 0
sp = 0
while p < 100:
    p += random.randint(1,3)
    if p > 100: p = 100
    bar = "█" * int(p/4) + "░" * (25 - int(p/4))
    col = random.choice(c)
    eta = int((100-p) * 0.03)
    sys.stdout.write("\\r" + col + s[sp%len(s)] + "\\033[0m" + " [" + bar + "] " + str(p) + "% | ETA " + str(eta) + "s | made by @fevber")
    sys.stdout.flush()
    sp += 1
    time.sleep(0.05)
sys.stdout.write("\\n")

